document.getElementById("calcApasxolhseonButton")?.addEventListener("click",async()=>{const e=document.getElementById("apo_hmeromhnia")?.value,t=document.getElementById("eos_hmeromhnia")?.value,o=document.getElementById("ypokatasthmata_stathera")?.value||"",a=document.getElementById("xronosProetoimasias_stathera")?.value||"",r=document.getElementById("proorhApoxorhsh_stathera")?.value||"";try{const s=await fetch("/ergazomenoi/programmata/calcApasxolhseisPeriodoy",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({apo_hmeromhnia:e,eos_hmeromhnia:t,ypokatasthmata_stathera:o,proorh_proseleysh:a,proorhApoxorhsh_stathera:r})}),n=await s.json();if(!n.success)return Swal.fire({icon:"warning",title:"Υπολογισμός Απασχολήσεων",text:n.message||"Ο υπολογισμός δεν ολοκληρώθηκε."});console.log(n),await Swal.fire({icon:"success",title:"Υπολογισμός Απασχολήσεων",text:`Βρέθηκαν ${n.employeesCount} εργαζόμενοι.`})}catch(e){console.error(e),await Swal.fire({icon:"error",title:"Υπολογισμός Απασχολήσεων",text:"Σφάλμα επικοινωνίας με τον server."})}});